  const runId = process.env.ZEALT_RUN_ID;
  const email = process.env.MAGICBELL_EMAIL;
  const [local, domain] = email.split('@');
  const email1 = `${local}+topic-subs-js-1-${runId}@${domain}`;

  console.log("Upserting User 1...");
  try {
    const res = await client.users.saveUser({
      external_id: `user-topic-subs-js-1-${runId}`,
      email: email1,
      first_name: 'TopicSubs',
      last_name: `One-${runId}`
    });
    console.log("User 1 upserted successfully:", res.data);
  } catch (err) {
    console.error("Error upserting User 1:", err);
  }
}

