const { RequestValidationHandler } = require('magicbell-js/dist/commonjs/project-client/http/handlers/request-validation-handler.js');
const { ResponseValidationHandler } = require('magicbell-js/dist/commonjs/project-client/http/handlers/response-validation-handler.js');

// Override RequestValidationHandler to bypass validation and serialize directly
RequestValidationHandler.prototype.validateRequest = function(request) {
  if (request.body !== undefined) {
    if (typeof request.body === 'object') {
      request.body = JSON.stringify(request.body);
    }
  }
};

// Override ResponseValidationHandler to bypass validation and return raw data
ResponseValidationHandler.prototype.validate = function(request, response, data) {
  return data;
};

