async function tryGet(url) {
  try {
    const res = await fetch(url, {
      headers: {
        'Authorization': `Bearer ${process.env.MAGICBELL_PROJECT_TOKEN}`
      }
    });
    console.log(`GET ${url} -> Status:`, res.status);
    if (res.status === 200) {
      const data = await res.json();
      console.log(`GET ${url} -> Data:`, JSON.stringify(data, null, 2));
    } else {
      console.log(`GET ${url} -> Text:`, await res.text());
    }
  } catch (err) {
    console.error(`Error GET ${url}:`, err);
  }
}

